import SectionC from "./components/landingPages/SectionC/SectionC";
import SectionD from "./components/landingPages/SectionD/SectionD";
import './App.css';



function App() {
  return (
    <div className="App">
      <Navbar />
      <Nav />
      <SectionA />
      <SectionB />
      <SectionC />
      <SectionD />
    </div>
  );
}

export default App;
